    fn test_heat_action_code() {
        assert_eq!(jjrn_HeatAction::Nominate.jjrn_code(), 'N');
        assert_eq!(jjrn_HeatAction::Slate.jjrn_code(), 'S');
        assert_eq!(jjrn_HeatAction::Rail.jjrn_code(), 'r');
        assert_eq!(jjrn_HeatAction::Tally.jjrn_code(), 'T');
