    fn test_format_notch_prefix() {
        let coronet = Coronet::jjrf_parse("ABAAA").unwrap();
        let prefix = jjrn_format_notch_prefix(&coronet);
        assert_eq!(prefix, "jjb:RBM:₢ABAAA:n: ");
