        assert_eq!(jjrn_ChalkMarker::jjrn_parse("Wrap").unwrap(), jjrn_ChalkMarker::Wrap);
        assert_eq!(jjrn_ChalkMarker::jjrn_parse("FLY").unwrap(), jjrn_ChalkMarker::Fly);
